SELECT committee_id, COUNT(*) AS action_count
  FROM actions
  GROUP BY committee_id;

SELECT MAX(action_date) 
FROM actions 
WHERE committee_id = 1;

SELECT MAX(meeting_date)
FROM meetings
WHERE committee_id = 1;

SELECT action_id
FROM actions
ORDER BY action_date DESC, committee_id, action_id;

SELECT action_id
FROM actions
ORDER BY action_date DESC, action_id DESC;

SELECT COUNT(committee_id) AS committee_count
FROM committees
WHERE founded_date > '2022-01-01';
